import React from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, CartesianGrid } from "recharts";

const BusTrendChart = ({ buses }) => {
  const counts = {
    normal: buses.filter(b => b.status === "normal").length,
    ghost: buses.filter(b => b.status === "ghost").length,
    anomaly: buses.filter(b => b.status === "anomaly").length
  };

  const trendData = [{ time: new Date().toLocaleTimeString(), ...counts }];

  return (
    <div style={{ width: "90%", margin: "20px auto", padding: "10px", borderRadius: "8px", background: "white" }}>
      <LineChart width={800} height={250} data={trendData}>
        <XAxis dataKey="time" />
        <YAxis />
        <Tooltip />
        <CartesianGrid stroke="#f5f5f5" />
        <Line type="monotone" dataKey="normal" stroke="green" />
        <Line type="monotone" dataKey="ghost" stroke="red" />
        <Line type="monotone" dataKey="anomaly" stroke="orange" />
      </LineChart>
    </div>
  );
};

export default BusTrendChart;
